#!/usr/bin/env node
/**
 * Generate LLM-friendly markdown files from Docusaurus sources.
 *
 * Reads guide MDX, demo MDX + separated code files, and API MDX,
 * then writes pure markdown to static/llm-docs/ and static/llms-full.txt.
 *
 * Generation targets are derived from:
 *   - Guide / Demo: sidebars.js (single source of truth)
 *   - API: docs/api/ directory scan (auto-generated by api-docs-generator)
 */

const fs = require("node:fs");
const path = require("node:path");

const DOCS_ROOT = path.join(__dirname, "..");
const DOCS_DIR = path.join(DOCS_ROOT, "docs");
const DEMO_SRC = path.join(DOCS_ROOT, "src", "demo");
const OUT_DIR = path.join(DOCS_ROOT, "static", "llm-docs");
const BASE_URL = "https://naver.github.io/egjs-flicking";

// ─── Sidebar parsing ────────────────────────────────────────────────────────

/** Extract flat list of doc IDs from a sidebar definition (handles categories) */
function flattenSidebarItems(items) {
  const result = [];
  for (const item of items) {
    if (typeof item === "string") {
      result.push(item);
    } else if (item && typeof item === "object" && item.items) {
      result.push(...flattenSidebarItems(item.items));
    }
  }
  return result;
}

function loadSidebars() {
  const sidebars = require(path.join(DOCS_ROOT, "sidebars.js"));
  return sidebars;
}

/** Read guide slugs from sidebars.js guideSidebar */
function getGuideSlugs() {
  const sidebars = loadSidebars();
  // IDs are like "guide/quickstart" → slug is "quickstart"
  return flattenSidebarItems(sidebars.guideSidebar).map(id => id.replace(/^guide\//, ""));
}

/** Read demo entries from sidebars.js demosSidebar, grouped by category */
function getDemoEntries() {
  const sidebars = loadSidebars();
  const entries = [];
  for (const item of sidebars.demosSidebar) {
    if (item && typeof item === "object" && item.items) {
      const ids = flattenSidebarItems(item.items);
      // IDs are like "demos/basic/default" → category "basic", slug "default"
      for (const id of ids) {
        const parts = id.replace(/^demos\//, "").split("/");
        if (parts.length === 2) {
          entries.push({ category: parts[0], slug: parts[1] });
        }
      }
    }
  }
  return entries;
}

/** Scan docs/api/ for all .mdx files */
function discoverAPITargets() {
  const apiDir = path.join(DOCS_DIR, "api");
  if (!fs.existsSync(apiDir)) return [];

  const targets = [];
  for (const sub of fs.readdirSync(apiDir)) {
    const subDir = path.join(apiDir, sub);
    if (!fs.statSync(subDir).isDirectory()) continue;
    for (const file of fs.readdirSync(subDir)) {
      if (file.endsWith(".mdx")) {
        targets.push(`${sub}/${file.replace(/\.mdx$/, "")}`);
      }
    }
  }
  return targets;
}

// ─── MDX → Markdown transformation ─────────────────────────────────────────

function extractFrontmatter(content) {
  const match = content.match(/^---\n([\s\S]*?)\n---\n/);
  if (!match) return { title: "", body: content };
  const fm = match[1];
  const titleMatch = fm.match(/title:\s*"?([^"\n]+)"?/);
  const title = titleMatch ? titleMatch[1] : "";
  const body = content.substring(match[0].length);
  return { title, body };
}

function removeImportsOutsideCodeBlocks(text) {
  const lines = text.split("\n");
  const result = [];
  let inCodeBlock = false;
  for (const line of lines) {
    if (line.startsWith("```")) inCodeBlock = !inCodeBlock;
    if (!inCodeBlock && /^import\s+/.test(line)) continue;
    result.push(line);
  }
  return result.join("\n");
}

function transformMdx(body) {
  let out = body;

  // Remove import lines (only outside code blocks)
  out = removeImportsOutsideCodeBlocks(out);

  // Tabs + TabItem → framework-labeled sections
  out = out.replace(/<Tabs[^>]*>/g, "");
  out = out.replace(/<\/Tabs>/g, "");
  out = out.replace(/<TabItem\s+value="[^"]*"\s+label="([^"]*)">/g, "\n**$1:**\n");
  out = out.replace(/<\/TabItem>/g, "");

  // Admonitions: :::type Title → > **Type: Title**
  out = out.replace(/^:::(info|warning|tip|danger)\s*(.*)?$/gm, (_, type, title) => {
    const label = type.charAt(0).toUpperCase() + type.slice(1);
    return title ? `> **${label}: ${title}**` : `> **${label}**`;
  });
  out = out.replace(/^:::$/gm, ""); // closing :::

  // Remove HTML wrapper divs
  out = out.replace(/<div\s+className="[^"]*">/g, "");
  out = out.replace(/<\/div>/g, "");

  // Convert relative .mdx links to absolute URLs
  out = out.replace(/\]\((\.\.[^)]*?)\.mdx(#[^)]*?)?\)/g, (_, relPath, hash) => {
    return `](${BASE_URL}/docs/${relPath.replace(/\.\.\//g, "")}${hash || ""})`;
  });

  // Relative links: any ../ prefixed path (with optional #hash)
  out = out.replace(/\]\(((?:\.\.\/)+)([\w/-]+)(#[\w-]*)?\)/g, (_, dots, rest, hash) => {
    return `](${BASE_URL}/docs/${rest}${hash || ""})`;
  });
  // ./slug links
  out = out.replace(/\]\(\.\/([\w-]+)\)/g, `](${BASE_URL}/docs/$1)`);

  // Clean up multiple blank lines
  out = out.replace(/\n{3,}/g, "\n\n");

  return out.trim();
}

// ─── Guide processing ───────────────────────────────────────────────────────

function processGuides() {
  const results = [];
  const guideDir = path.join(DOCS_DIR, "guide");
  const outDir = path.join(OUT_DIR, "guide");
  fs.mkdirSync(outDir, { recursive: true });

  for (const slug of getGuideSlugs()) {
    const src = path.join(guideDir, `${slug}.mdx`);
    if (!fs.existsSync(src)) {
      console.warn(`  ⚠ guide/${slug}.mdx not found, skipping`);
      continue;
    }
    const raw = fs.readFileSync(src, "utf-8");
    const { title, body } = extractFrontmatter(raw);
    const transformed = transformMdx(body);
    const md = transformed.startsWith(`# ${title}`) ? transformed : `# ${title}\n\n${transformed}`;

    const outPath = path.join(outDir, `${slug}.md`);
    fs.writeFileSync(outPath, `${md}\n`);
    results.push({ path: `guide/${slug}.md`, content: md });
    console.log(`  ✓ guide/${slug}.md`);
  }

  return results;
}

// ─── Demo processing ────────────────────────────────────────────────────────

function findDemoDir(category, mdxSlug) {
  const mdxPath = path.join(DOCS_DIR, "demos", category, `${mdxSlug}.mdx`);
  if (!fs.existsSync(mdxPath)) return null;

  const content = fs.readFileSync(mdxPath, "utf-8");
  const match = content.match(/import\s+(\w+)\s+from\s+['"]@site\/src\/demo\/\w+\/(\w+)['"]/);
  if (match) return match[2];
  return null;
}

function readDemoCode(category, dirName) {
  const dir = path.join(DEMO_SRC, category, dirName);
  if (!fs.existsSync(dir)) return null;

  const read = file => {
    const p = path.join(dir, file);
    return fs.existsSync(p) ? fs.readFileSync(p, "utf-8").trim() : null;
  };

  return {
    react: read("react.jsx"),
    vue: read("vue.vue"),
    js: read("vanilla.js"),
    html: read("index.html"),
    css: read("styles.css")
  };
}

function processDemos() {
  const results = [];

  // Group entries by category to create output dirs
  const byCategory = new Map();
  for (const { category, slug } of getDemoEntries()) {
    if (!byCategory.has(category)) byCategory.set(category, []);
    byCategory.get(category).push(slug);
  }

  for (const [category, slugs] of byCategory) {
    const outDir = path.join(OUT_DIR, "demos", category);
    fs.mkdirSync(outDir, { recursive: true });

    for (const slug of slugs) {
      const mdxPath = path.join(DOCS_DIR, "demos", category, `${slug}.mdx`);
      if (!fs.existsSync(mdxPath)) {
        console.warn(`  ⚠ demos/${category}/${slug}.mdx not found, skipping`);
        continue;
      }

      const raw = fs.readFileSync(mdxPath, "utf-8");
      const { title, body } = extractFrontmatter(raw);

      const dirName = findDemoDir(category, slug);
      const code = dirName ? readDemoCode(category, dirName) : null;

      let transformed = transformMdx(body);
      transformed = transformed.replace(/<\w+\s*\/>/g, "");

      let md = transformed.startsWith(`# ${title}`) ? transformed : `# ${title}\n\n${transformed}`;

      if (code) {
        md += "\n\n## Code\n";
        if (code.react) md += `\n### React\n\`\`\`jsx\n${code.react}\n\`\`\`\n`;
        if (code.vue) md += `\n### Vue3\n\`\`\`vue\n${code.vue}\n\`\`\`\n`;
        if (code.js) md += `\n### JavaScript\n\`\`\`js\n${code.js}\n\`\`\`\n`;
        if (code.html) md += `\n### HTML (for vanilla JS)\n\`\`\`html\n${code.html}\n\`\`\`\n`;
        if (code.css) md += `\n### CSS\n\`\`\`css\n${code.css}\n\`\`\`\n`;
      }

      const outPath = path.join(outDir, `${slug}.md`);
      fs.writeFileSync(outPath, `${md.trim()}\n`);
      results.push({ path: `demos/${category}/${slug}.md`, content: md.trim() });
      console.log(`  ✓ demos/${category}/${slug}.md`);
    }
  }

  return results;
}

// ─── API processing ─────────────────────────────────────────────────────────

function processAPIs() {
  const results = [];

  const apiTargets = discoverAPITargets();
  if (apiTargets.length === 0) {
    console.warn("  ⚠ docs/api/ not found or empty (run api-docs-generator first)");
  }

  for (const relPath of apiTargets) {
    const mdxPath = path.join(DOCS_DIR, "api", `${relPath}.mdx`);
    if (!fs.existsSync(mdxPath)) continue;

    const raw = fs.readFileSync(mdxPath, "utf-8");
    const { title, body } = extractFrontmatter(raw);

    let transformed = body;

    transformed = transformed.replace(/<div\s+className="api-\w+">/g, "");
    transformed = transformed.replace(/<\/div>/g, "");

    transformed = transformed.replace(/\]\(([./]*[\w/-]+)\.mdx(#[\w-]*)?\)/g, (_, relLink, hash) => {
      const cleaned = relLink.replace(/^\.\//, "").replace(/^\.\.\//g, "");
      return `](${BASE_URL}/docs/api/${cleaned}${hash || ""})`;
    });

    transformed = removeImportsOutsideCodeBlocks(transformed);
    transformed = transformed.replace(/\n{3,}/g, "\n\n");
    transformed = transformed.trim();

    const md = transformed.startsWith(`# ${title}`) ? transformed : `# ${title}\n\n${transformed}`;

    const dir = path.dirname(relPath);
    const base = path.basename(relPath);
    const outDir = path.join(OUT_DIR, "api", dir);
    fs.mkdirSync(outDir, { recursive: true });

    const outPath = path.join(outDir, `${base}.md`);
    fs.writeFileSync(outPath, `${md.trim()}\n`);
    results.push({ path: `api/${relPath}.md`, content: md.trim() });
    console.log(`  ✓ api/${relPath}.md`);
  }

  return results;
}

// ─── Post-process: rewrite /docs/ links inside generated .md files ──────────

function rewriteLinksInGeneratedDocs(allResults) {
  const generated = new Set(allResults.map(r => r.path));

  const byName = new Map();
  const byFullPath = new Map();

  for (const p of generated) {
    const noExt = p.replace(/\.md$/, "");
    byFullPath.set(noExt, p);
    const name = path.basename(noExt);
    byName.set(name, p);
  }

  function resolve(docPath) {
    const parts = docPath.split("/").filter(Boolean);
    const normalized = [];
    for (const part of parts) {
      if (part === "..") normalized.pop();
      else if (part !== ".") normalized.push(part);
    }
    const norm = normalized.join("/");

    if (byFullPath.has(norm)) return byFullPath.get(norm);

    const withDemos = `demos/${norm}`;
    if (byFullPath.has(withDemos)) return byFullPath.get(withDemos);

    if (norm.startsWith("api/")) {
      const bareName = normalized[normalized.length - 1];
      if (byName.has(bareName)) return byName.get(bareName);
    }

    if (!norm.includes("/") && byName.has(norm)) return byName.get(norm);

    return null;
  }

  const linkRe = /https:\/\/naver\.github\.io\/egjs-flicking\/docs\/([\w./-]+?)(#[\w-]*)?(?=\)|\s|$)/g;

  let filesUpdated = 0;

  for (const result of allResults) {
    const filePath = path.join(OUT_DIR, result.path);
    let content = fs.readFileSync(filePath, "utf-8");
    let changed = false;

    content = content.replace(linkRe, (match, docPath, hash) => {
      const resolved = resolve(docPath);
      if (resolved) {
        changed = true;
        return `${BASE_URL}/llm-docs/${resolved}${hash || ""}`;
      }
      return match;
    });

    if (changed) {
      fs.writeFileSync(filePath, content);
      result.content = content.trim();
      filesUpdated++;
    }
  }

  console.log(`  ✓ ${filesUpdated} files updated`);
}

// ─── llms-full.txt generation ───────────────────────────────────────────────

function generateLlmsFullTxt(allResults) {
  const parts = [];

  for (const { path: relPath, content } of allResults) {
    parts.push(`--- ${relPath} ---\n\n${content}`);
  }

  const fullPath = path.join(DOCS_ROOT, "static", "llms-full.txt");
  fs.writeFileSync(fullPath, `${parts.join("\n\n---\n\n")}\n`);
  console.log(`  ✓ llms-full.txt (${allResults.length} documents)`);
}

// ─── Main ───────────────────────────────────────────────────────────────────

console.log("Generating LLM docs...\n");

if (fs.existsSync(OUT_DIR)) {
  fs.rmSync(OUT_DIR, { recursive: true });
}
fs.mkdirSync(OUT_DIR, { recursive: true });

console.log("Guide docs:");
const guideResults = processGuides();

console.log("\nDemo docs:");
const demoResults = processDemos();

console.log("\nAPI docs:");
const apiResults = processAPIs();

const allResults = [...guideResults, ...demoResults, ...apiResults];

console.log("\nRewriting links in generated docs:");
rewriteLinksInGeneratedDocs(allResults);

console.log("\nGenerating full text:");
generateLlmsFullTxt(allResults);

const total = guideResults.length + demoResults.length + apiResults.length;
console.log(`\nDone: ${total} documents generated in static/llm-docs/`);
